// admin/src/services/productService.js
import api from './axiosClient';

class ProductService {
    async getAllProducts() {
        const res = await api.get('/admin/products/products');
        return res.data;
    }

    async getAllCategories() {
        const res = await api.get('/admin/categories/category');
        return res.data;
    }

    async saveProduct(productData, isEdit) {
        const url = `/admin/products${isEdit ? '/' + productData.product_id : ''}`;
        const method = isEdit ? 'put' : 'post';
        return await api[method](url, productData);
    }

    async deleteProduct(id) {
        return await api.delete(`/admin/products/${id}`);
    }
}

export default new ProductService();
